import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

class IssueControllerTest {

    private IssueRepository repository;
    private IssueController controller;

    @BeforeEach
    void setUp() {
        repository = mock(IssueRepository.class);
        controller = new IssueController(repository);
    }

    @Test
    void createIssue_returnsNewOpenIssueWithGivenTitleAndPriority() {
        Issue saved = new Issue("abc-123", "Login page crashes", "HIGH", "OPEN");
        when(repository.save(any())).thenReturn(saved);

        Issue result = controller.createIssue("Login page crashes", "HIGH");

        assertEquals("Login page crashes", result.getTitle());
        assertEquals("HIGH", result.getPriority());
        assertEquals("OPEN", result.getStatus());
    }

    @Test
    void createIssue_throwsWhenTitleIsBlank() {
        assertThrows(
            IllegalArgumentException.class,
            () -> controller.createIssue("", "LOW")
        );
        verifyNoInteractions(repository);
    }
}
